targets.expr:
label_replace(
  max by (dimension_TargetGroup) (
    last_over_time(
      aws_applicationelb_healthy_host_count_minimum[$__range]
    )
  ),
  "target_group", "$1", "dimension_TargetGroup", "(.*)"
)
* on(target_group) group_left()
aws_target_group_info{exported_namespace="istio-system", exported_service="istio-ingress", target_group=~"$target_group"}

label_replace(
  max by (dimension_TargetGroup) (
    last_over_time(
      aws_applicationelb_un_healthy_host_count_minimum[$__range]
    )
  ),
  "target_group", "$1", "dimension_TargetGroup", "(.*)"
)
* on(target_group) group_left()
aws_target_group_info{exported_namespace="istio-system", exported_service="istio-ingress", target_group=~"$target_group"}
